class Solution:
    def canBeIncreasing(self, nums):
        def inc(arr):
            return all(arr[i - 1] < arr[i] for i in range(1, len(arr)))
        if inc(nums):
            return True
        for i in range(len(nums)):
            if inc(nums[:i] + nums[i + 1:]):
                return True
        return False

